#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d",&N,&Q);
        int *a = (int*)malloc((N+2)*sizeof(int));
        for(int i=1;i<=N;i++) scanf("%d",&a[i]);
        long long runs = 1;
        for(int i=2;i<=N;i++) if(a[i]!=a[i-1]) runs++;
        while(Q--){
            int x,y; scanf("%d %d",&x,&y);
            if(N>1){
                if(x>1){ if(a[x]!=a[x-1]) runs--; if(y!=a[x-1]) runs++; }
                if(x<N){ if(a[x+1]!=a[x]) runs--; if(a[x+1]!=y) runs++; }
            }
            a[x]=y;
            printf("%lld\n",runs);
        }
        free(a);
    }
    return 0;
}

