import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            int[] a = new int[N + 2];
            for (int i = 1; i <= N; i++) a[i] = fs.nextInt();
            long runs = 1;
            for (int i = 2; i <= N; i++) if (a[i] != a[i - 1]) runs++;
            while (Q-- > 0) {
                int x = fs.nextInt();
                int y = fs.nextInt();
                if (N > 1) {
                    if (x > 1) {
                        if (a[x] != a[x - 1]) runs--;
                        if (y != a[x - 1]) runs++;
                    }
                    if (x < N) {
                        if (a[x + 1] != a[x]) runs--;
                        if (a[x + 1] != y) runs++;
                    }
                }
                a[x] = y;
                out.append(runs).append('\n');
            }
        }
        System.out.print(out.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign;
        }
    }
}

