import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    t = next(it)
    out_lines = []
    for _ in range(t):
        n = next(it); q = next(it)
        a = [0] + [next(it) for _ in range(n)]
        runs = 1
        for i in range(2, n+1):
            if a[i] != a[i-1]:
                runs += 1
        for _ in range(q):
            x = next(it); y = next(it)
            if n > 1:
                if x > 1:
                    if a[x] != a[x-1]:
                        runs -= 1
                    if y != a[x-1]:
                        runs += 1
                if x < n:
                    if a[x+1] != a[x]:
                        runs -= 1
                    if a[x+1] != y:
                        runs += 1
            a[x] = y
            out_lines.append(str(runs))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

